using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 changed the discriminator property from "Discriminator" to "$type".
        // Preserve the old name so existing 500K documents remain readable.
        configurationBuilder.Conventions.Remove(
            typeof(Microsoft.EntityFrameworkCore.Cosmos.Metadata.Conventions.CosmosDiscriminatorConvention));
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Restore the EF Core 8 discriminator property name and value so that
            // existing documents (c.Discriminator = 'Product') keep working,
            // including raw SQL queries against the container.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // EF Core 9 changed the id format from "EntityType|Key" to just "Key".
            // Use a value generator to preserve the "Product|<id>" format for
            // backward compatibility with existing documents.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<ProductIdValueGenerator>();
        });
    }
}

class Product
{
    public int Id { get; set; }
    public string Sku { get; set; } = string.Empty;
}

// Preserves the EF Core 8 "Product|<key>" id format in Cosmos documents.
class ProductIdValueGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(Microsoft.EntityFrameworkCore.ChangeTracking.EntityEntry entry)
    {
        var id = entry.Property("Id").CurrentValue;
        return $"Product|{id}";
    }
}

